Skill.ParameterSchema:
{
    "$schema": "https://json-schema.org/draft/2020-12/schema",
    "type": "object",
    "required": ["code"],
    "properties": {
      "code": {
        "type": "string",
        "minLength": 1,
        "maxLength": 16384,
        "description": "C# script body. Script globals: Services (IServiceProvider), CallerId (string), Write/WriteLine for output."
      }
    },
    "additionalProperties": false
  }
